# ==================== 数据总览页面（三方联动） ====================
def create_data_page():
    lang = st.session_state.get("lang", "zh")

    st.markdown(f"<h1 style='font-size:2rem !important;margin-bottom:0;'>📊 {t('nav_data', lang)}</h1>", unsafe_allow_html=True)
    st.markdown(f"<p style='color:#64748B;margin-bottom:24px;'>{t('home_data_desc', lang)}</p>", unsafe_allow_html=True)

    # 初始化数据
    if st.session_state.recipe_data is None:
        st.session_state.recipe_data = get_sample_recipe_data()
    if st.session_state.perf_data is None:
        st.session_state.perf_data = get_sample_perf_data()
    if st.session_state.char_data is None:
        st.session_state.char_data = get_sample_char_data()

    # ========== 第一部分：配方表格 ==========
    st.markdown(f"<h3>{t('data_recipe_title', lang)}</h3>", unsafe_allow_html=True)
    st.caption(t("data_recipe_hint", lang))

    recipe_df = st.session_state.recipe_data
    selected = st.session_state.get("selected_row")

    # 配方表格 - 可点击选择行（联动驱动）
    sel_event = st.dataframe(
        recipe_df,
        key="recipe_select",
        use_container_width=True,
        hide_index=False,
        on_select="rerun",
        selection_mode="single-row",
        column_config={
            "样品名称": st.column_config.TextColumn(t("data_recipe_col_name", lang)),
            "二酐单体": st.column_config.TextColumn(t("data_recipe_col_dianhy", lang)),
            "二胺单体": st.column_config.TextColumn(t("data_recipe_col_diamine", lang)),
            "溶剂": st.column_config.TextColumn(t("data_recipe_col_solvent", lang)),
            "合成方法": st.column_config.TextColumn(t("data_recipe_col_method", lang)),
        }
    )
    # 从选择事件更新 selected_row
    if sel_event and sel_event["selection"]["rows"]:
        st.session_state.selected_row = sel_event["selection"]["rows"][0] + 1
    elif sel_event and not sel_event["selection"]["rows"]:
        st.session_state.selected_row = None

    # 编辑按钮 + 清除高亮
    col_ed, col_cl, _ = st.columns([0.2, 0.2, 0.6])
    with col_ed:
        edit_mode = st.checkbox("✏️ 编辑表格", key="edit_recipe_mode")
    with col_cl:
        if st.button("清除高亮", key="clear_highlight"):
            st.session_state.selected_row = None
            st.rerun()

    # 编辑模式：弹出一个 data_editor
    if edit_mode:
        st.info("📝 双击单元格编辑内容，完成后取消勾选「编辑表格」即回到选择模式")
        edited_recipe = st.data_editor(
            st.session_state.recipe_data,
            key="recipe_editor",
            use_container_width=True,
            hide_index=False,
            num_rows="dynamic",
            column_config={
                "样品名称": st.column_config.TextColumn(t("data_recipe_col_name", lang)),
                "二酐单体": st.column_config.TextColumn(t("data_recipe_col_dianhy", lang)),
                "二胺单体": st.column_config.TextColumn(t("data_recipe_col_diamine", lang)),
                "溶剂": st.column_config.TextColumn(t("data_recipe_col_solvent", lang)),
                "合成方法": st.column_config.TextColumn(t("data_recipe_col_method", lang)),
            }
        )
        if edited_recipe is not None:
            st.session_state.recipe_data = edited_recipe

    st.markdown("---")

    # ========== 第二部分：性能表格 ==========
    st.markdown(f"<h3>{t('data_perf_title', lang)}</h3>", unsafe_allow_html=True)
    st.caption(t("data_perf_hint", lang))

    perf_df = st.session_state.perf_data
    # 确保性能表格行数与配方一致（自动扩展/缩减）
    if len(perf_df) != len(st.session_state.recipe_data):
        diff = len(st.session_state.recipe_data) - len(perf_df)
        if diff > 0:
            new_rows = pd.DataFrame({col: [""] * diff for col in perf_df.columns})
            perf_df = pd.concat([perf_df, new_rows], ignore_index=True)
        elif diff < 0:
            perf_df = perf_df.iloc[:len(st.session_state.recipe_data)].reset_index(drop=True)
        st.session_state.perf_data = perf_df

    edited_perf = st.data_editor(
        st.session_state.perf_data,
        key="perf_editor",
        use_container_width=True,
        hide_index=False,
        num_rows="dynamic",
        column_config={
            "样品名称": st.column_config.TextColumn(t("data_perf_col_name", lang)),
            "Tg (°C)": st.column_config.NumberColumn(t("data_perf_col_tg", lang)),
            "Td (°C)": st.column_config.NumberColumn(t("data_perf_col_td", lang)),
            "介电常数": st.column_config.NumberColumn(t("data_perf_col_dielectric", lang)),
            "拉伸强度(MPa)": st.column_config.NumberColumn(t("data_perf_col_tensile", lang)),
            "断裂伸长率(%)": st.column_config.NumberColumn(t("data_perf_col_elongation", lang)),
        }
    )
    if edited_perf is not None:
        st.session_state.perf_data = edited_perf

    st.markdown("---")

    # ========== 第三部分：表征图表 ==========
    st.markdown(f"<h3>{t('data_char_title', lang)}</h3>", unsafe_allow_html=True)
    st.caption(t("data_char_hint", lang))

    char_df = st.session_state.char_data
    # 确保表征表格行数与配方一致
    if len(char_df) != len(st.session_state.recipe_data):
        diff = len(st.session_state.recipe_data) - len(char_df)
        if diff > 0:
            new_rows = pd.DataFrame({col: [""] * diff for col in char_df.columns})
            char_df = pd.concat([char_df, new_rows], ignore_index=True)
        elif diff < 0:
            char_df = char_df.iloc[:len(st.session_state.recipe_data)].reset_index(drop=True)
        char_df["预览图路径"] = char_df.get("预览图路径", [None] * len(char_df))
        st.session_state.char_data = char_df

    # 显示表征 — 按样品名称分组折叠
    char_df = st.session_state.char_data
    sel = st.session_state.selected_row

    # 获取当前选中行的样品名称
    selected_sample = None
    if sel is not None:
        recipe_names = st.session_state.recipe_data["样品名称"].tolist()
        if 1 <= sel <= len(recipe_names):
            selected_sample = recipe_names[sel - 1]

    for sample_name in char_df["样品名称"].unique():
        group = char_df[char_df["样品名称"] == sample_name]
        is_active = (sample_name == selected_sample)
        active_class = "active" if is_active else ""

        with st.expander(f"📁 {sample_name} ({len(group)} 项表征)", expanded=is_active):
            for idx, row in group.iterrows():
                c1, c2, c3, c4 = st.columns([1, 0.5, 2, 1])
                with c1:
                    st.markdown(f"<div class='char-card {active_class}' style='padding:12px;'>"
                                f"<strong style='color:#0F172A;'>{row.get('表征类型', '')}</strong></div>",
                                unsafe_allow_html=True)
                with c2:
                    img_path = row.get("预览图路径")
                    if pd.notna(img_path) and Path(str(img_path)).exists():
                        st.image(img_path, width=120)
                    else:
                        st.markdown(f"<div class='char-card {active_class}' style='padding:16px;'>"
                                    f"<span style='color:#CBD5E1;font-size:0.85rem;'>{t('data_char_no_image', lang)}</span></div>",
                                    unsafe_allow_html=True)
                with c3:
                    st.markdown(f"<div class='char-card {active_class}' style='padding:12px;'>"
                                f"<span style='color:#64748B;font-size:0.85rem;'>{row.get('样品名称', '')}</span></div>",
                                unsafe_allow_html=True)
                with c4:
                    if st.button(f"🔍 详情", key=f"char_detail_{idx}"):
                        st.session_state.show_char_detail = True
                        st.session_state.char_detail_idx = idx
                        st.rerun()

    st.markdown("<br>", unsafe_allow_html=True)

    # 表征图详情弹窗
    if st.session_state.get("show_char_detail") and st.session_state.char_detail_idx is not None:
        idx = st.session_state.char_detail_idx
        row = st.session_state.char_data.iloc[idx]
        with st.expander(f"🔍 {row.get('样品名称', '')} - {row.get('表征类型', '')}", expanded=True):
            img_path = row.get("预览图路径")
            if pd.notna(img_path) and Path(str(img_path)).exists():
                st.image(img_path, use_container_width=True)
            else:
                st.info(t("data_char_no_image", lang))

            st.markdown(f"""
            <div style="background:#F8FAFC;border-radius:12px;padding:16px;margin-top:12px;">
                <p style="color:#64748B;margin:0;"><strong>{t("data_recipe_col_name", lang)}:</strong> {row.get('样品名称', '')}</p>
                <p style="color:#64748B;margin:8px 0 0 0;"><strong>{t("data_char_col_type", lang)}:</strong> {row.get('表征类型', '')}</p>
                <p style="color:#64748B;margin:8px 0 0 0;"><strong>Path:</strong> {img_path or 'N/A'}</p>
            </div>
            """, unsafe_allow_html=True)

            if st.button("✖ 关闭详情", key="close_char_detail"):
                st.session_state.show_char_detail = False
                st.session_state.char_detail_idx = None
                st.rerun()

    st.markdown("<br>", unsafe_allow_html=True)

    # 底部说明联动效果
    if st.session_state.selected_row:
        st.success(f"✅ 当前选中行: **{st.session_state.selected_row}** — "
                   f"配方 · 性能 · 表征 三方联动高亮中")


